Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
lib/dirty/dirty.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict';

const fs = require('fs');
const EventEmitter = require('events').EventEmitter;

class Dirty extends EventEmitter {
  constructor(path) {
    super();

    this.path = path;

    this._data = new Map();
    this._queue = new Map(); // Maps key to a list of callbacks.
    this._readStream = null;
    this._writeStream = null;
    this._waitForDrain = false;
    this._inFlightWrites = 0;

    this._load();
  }

  /**
   * set() stores a JSON object in the database at key
   * cb is fired when the data is persisted.
   * In memory, this is immediate - on disk, it will take some time.
   */
  set(key, val, cb) {
    if (val === undefined) {
      this._data.delete(key);
    } else {
      this._data.set(key, val);
    }
    if (this.path) {
      const cbs = this._queue.get(key) || [];
      if (cb) cbs.push(cb);
      this._queue.set(key, cbs);
      this._flush();
    } else {
      setImmediate(() => { if (cb) cb(); this.emit('drain'); });
    }
  }

  /**
   * Get the value stored at a key in the database
   * This is synchronous since a cache is maintained in-memory
   */
  get(key) {
    return this._data.get(key);
  }

  /**
   * Get total number of stored keys
   */
  size() {
    return this._data.size;
  }

  /**
   * Remove a key and the value stored there
   */
  rm(key, cb) {
    this.set(key, undefined, cb);
  }

  /**
   * Iterate over keys, applying match function
   */
  forEach(fn) {
    for (const [key, val] of this._data) {
      if (fn(key, val) === false) break;
    }
  }

  /**
   * Update the value stored at a key in the database.
   * This is synchronous since a cache is maintained in-memory
   * cb is passed as per Dirty.prototype.set
   */
  update(key, updater, cb) {
    this.set(key, updater(this.get(key)), cb);
  }

  /**
   * Close dirty db file streams
   */
  close() {
    if (this._queue.size || this._inFlightWrites > 0) {
      this.once('drain', () => this.close());
      return;
    }
    if (this._readStream) this._readStream.destroy();
    if (this._writeStream) this._writeStream.end(() => this._writeStream.destroy());
  }

  // Called when a dirty connection is instantiated
  _load() {
    let buffer = '';

    if (!this.path) {
      process.nextTick(() => {
        this.emit('load', 0);
      });
      return;
    }

    this._readStream = fs.createReadStream(this.path, {
      encoding: 'utf-8',
      flags: 'r',
    });

    this._readStream
        .on('error', (err) => {
          if (err.code === 'ENOENT') {
            this.emit('load', 0);
            return;
          }

          this.emit('error', err);
        })
        .on('data', (chunk) => {
          buffer += chunk;
          if (chunk.lastIndexOf('\n') === -1) return;
          const arr = buffer.split('\n');
          buffer = arr.pop();
          arr.forEach((rowStr) => {
            if (!rowStr) {
              this.emit('error', new Error('Empty lines never appear in a healthy database'));
              return;
            }

            let row;
            try {
              row = JSON.parse(rowStr);
              if (!('key' in row)) {
                throw new Error();
              }
            } catch (e) {
              this.emit('error', new Error(`Could not load corrupted row: ${rowStr}`));
              return '';
            }

            if (row.val === undefined) {
              this._data.delete(row.key);
            } else {
              this._data.set(row.key, row.val);
            }
            return '';
          });
        })
        .on('end', () => {
          if (buffer.length) {
            this.emit('error', new Error(`Corrupted row at the end of the db: ${buffer}`));
          }
          this.emit('load', this._data.size);
        })
        .on('close', () => {
          this._readStream = null;
          this.emit('read_close');
        });

    this._writeStream = fs.createWriteStream(this.path, {
      encoding: 'utf-8',
      flags: 'a',
    });

    this._writeStream.on('drain', () => {
      this._waitForDrain = false;
      if (!this._queue.size) {
        if (this._inFlightWrites <= 0) this.emit('drain');
         } else {}

    });

    this._writeStream.on('close', () => {
      this._writeStream = null;
      this.emit('write_close');
    });
  }

  _flush() {
    if (!this._queue.size || this._waitForDrain) return;
    <PLACEHOLDER>
    for (const [key, cbs] of this._queue) {
      this._queue.delete(key);
      const data = `${JSON.stringify({key, val: this._data.get(key)})}\n`;
      ++this._inFlightWrites;
      this._waitForDrain = !this._writeStream.write(data, (err) => {
        if (!cbs.length && err != null) this.emit('error', err);
        if (--this._inFlightWrites <= 0 && !this._waitForDrain) this.emit('drain');
        for (const cb of cbs) cb(err);
      });
      if (this._waitForDrain) break;
    }
    this._writeStream.uncork();
  }
}

Dirty.Dirty = Dirty;
// Trap `apply` for backwards compatibility with callers that don't use `new`.
module.exports = exports = new Proxy(Dirty, {apply: (target, thisArg, args) => new Dirty(...args)});

In the original code, <PLACEHOLDER> has the value:

-       if (!this._queue.size || this._waitForDrain) return;
In the mutated code, <PLACEHOLDER> has the value:

+       if (false) return;


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/node-dirty/attempt_1/pending_category/mutant-56e874a/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).
    2. The following external libraries are explicitly permitted:
    - rimraf
You may not use any other third-party libraries.

Looking at the mutation, the original code has a guard at the top of `_flush()`:
```javascript
if (!this._queue.size || this._waitForDrain) return;
```

The mutated code replaces this with:
```javascript
if (false) return;
```

This means the mutated code will **never** return early when `_waitForDrain` is true. The `_waitForDrain` flag is set when the write stream's buffer is full and needs to drain before more data can be written. Without this guard, the code will continue writing even when it should be waiting for drain.

The key behavioral difference: when `_waitForDrain` is true, the original code stops flushing, but the mutated code continues. This means the mutated code could write data even when the stream signals backpressure.

I need to test a scenario where `_waitForDrain` gets set to `true` and then `_flush()` is called again - in the original, it would return early; in the mutated version, it would proceed.

Actually, looking more carefully: the `_waitForDrain` is set by `this._waitForDrain = !this._writeStream.write(...)`. When `write()` returns `false`, `_waitForDrain` becomes `true`. Then if `_flush()` is called again while `_waitForDrain` is true, the original returns early, but the mutation doesn't.

I can test this by using a path-based dirty db, setting multiple keys rapidly, and checking that the drain event fires correctly and all data is persisted properly.

```typescript
import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';
import { rimraf } from 'rimraf';
import Dirty from '../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js';

describe('Dirty _flush waitForDrain guard', () => {
  it('should not write to stream when _waitForDrain is true, preventing double-cork/uncork issues', (done) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
    const dbPath = path.join(tmpDir, 'test.db');

    const db = new Dirty(dbPath);

    db.on('load', () => {
      // Monkey-patch the write stream to simulate backpressure on first write
      const originalWrite = db._writeStream.write.bind(db._writeStream);
      let writeCount = 0;

      db._writeStream.write = function(data, cb) {
        writeCount++;
        if (writeCount === 1) {
          // Simulate backpressure: return false to set _waitForDrain = true
          originalWrite(data, cb);
          return false;
        }
        return originalWrite(data, cb);
      };

      // Set a key - this triggers _flush, which will set _waitForDrain = true
      db.set('key1', 'value1');

      // At this point _waitForDrain should be true
      // Now call set again - in original code, _flush returns early due to _waitForDrain guard
      // In mutated code, _flush proceeds and calls cork/uncork again without proper state
      db.set('key2', 'value2');

      // The drain event should eventually fire and all data should be readable
      db.on('drain', () => {
        // Verify both keys are in memory
        const val1 = db.get('key1');
        const val2 = db.get('key2');

        expect(val1).toBe('value1');
        expect(val2).toBe('value2');

        db.close();
        db.on('write_close', () => {
          // Verify data was persisted correctly to disk
          const content = fs.readFileSync(dbPath, 'utf-8');
          const lines = content.trim().split('\n').filter(Boolean);

          // Each key should appear at least once
          const rows = lines.map(l => JSON.parse(l));
          const key1Row = rows.find(r => r.key === 'key1');
          const key2Row = rows.find(r => r.key === 'key2');

          expect(key1Row).toBeDefined();
          expect(key1Row.val).toBe('value1');
          expect(key2Row).toBeDefined();
          expect(key2Row.val).toBe('value2');

          rimraf(tmpDir).then(() => done()).catch(done);
        });
      });
    });

    db.on('error', done);
  });
});
```

Wait, this test might not reliably distinguish the mutation. Let me think more carefully about what the mutation actually breaks.

The mutation removes the `_waitForDrain` check, so `_flush` will call `cork()` and `uncork()` even when `_waitForDrain` is true. This could cause `uncork()` to be called multiple times without matching `cork()` calls, potentially causing data to be flushed prematurely.

Let me write a simpler, more reliable test:

```typescript
import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';
import { rimraf } from 'rimraf';
import Dirty from '../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js';

describe('Dirty _flush waitForDrain guard', () => {
  it('should respect _waitForDrain flag and not flush when stream needs to drain', (done) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
    const dbPath = path.join(tmpDir, 'test.db');

    const db = new Dirty(dbPath);
    let uncorkCount = 0;

    db.on('load', () => {
      const originalUncork = db._writeStream.uncork.bind(db._writeStream);
      db._writeStream.uncork = function() {
        uncorkCount++;
        return originalUncork();
      };

      const originalWrite = db._writeStream.write.bind(db._writeStream);
      let firstWrite = true;
      db._writeStream.write = function(data, cb) {
        if (firstWrite) {
          firstWrite = false;
          originalWrite(data, cb);
          return false; // signal backpressure
        }
        return originalWrite(data, cb);
      };

      db.set('key1', 'value1');
      // _waitForDrain is now true, so calling set again should NOT trigger another flush
      const uncorkAfterFirst = uncorkCount;
      db.set('key2', 'value2');

      // In original: second set queues key2 but _flush returns early (uncork not called again)
      // In mutated: second set causes _flush to run again, calling uncork again
      const uncorkAfterSecond = uncorkCount;

      db.on('drain', () => {
        // In original code, uncork should only be called once before drain
        // (the second _flush call returns early due to _waitForDrain guard)
        // In mutated code, uncork gets called twice
        expect(uncorkAfterSecond).toBe(uncorkAfterFirst);

        rimraf(tmpDir).then(() => done()).catch(done);
      });
    });

    db.on('error', done);
  });
});
```

