describe('Dirty _flush waitForDrain guard', () => {
  it('should not call uncork multiple times when _waitForDrain is true', (done) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
    const dbPath = path.join(tmpDir, 'test.db');

    const db = new Dirty(dbPath);
    let uncorkCount = 0;

    db.on('load', () => {
      const originalUncork = db._writeStream.uncork.bind(db._writeStream);
      db._writeStream.uncork = function() {
        uncorkCount++;
        return originalUncork();
      };

      const originalWrite = db._writeStream.write.bind(db._writeStream);
      let firstWrite = true;
      db._writeStream.write = function(data, cb) {
        if (firstWrite) {
          firstWrite = false;
          originalWrite(data, cb);
          return false; // signal backpressure - sets _waitForDrain = true
        }
        return originalWrite(data, cb);
      };

      // First set: triggers _flush, writes key1, sets _waitForDrain=true, calls uncork once
      db.set('key1', 'value1');

      // Second set: queues key2, calls _flush
      // Original: _flush sees _waitForDrain=true, returns early (no additional uncork)
      // Mutated: _flush ignores _waitForDrain, proceeds to cork/write/uncork again
      db.set('key2', 'value2');

      const uncorkCountAfterSets = uncorkCount;

      db.on('drain', () => {
        // Original: uncork called exactly once (for key1 flush only)
        // Mutated: uncork called twice (for key1 and key2 flushes)
        expect(uncorkCountAfterSets).toBe(1);
        rimraf(tmpDir).then(() => done()).catch(done);
      });
    });

    db.on('error', done);
  });
});
